const rulesContent = {
  en: `
<h1>Game Rules</h1>
<h2>About the Game</h2>
<p>Sport Predictions is a game where you predict the exact score of football matches played during
regular time (90 minutes). Every correctly guessed result earns you <strong>1 point</strong>.
Players can compete individually — choosing their favourite leagues in their personal account —
or in groups with friends by setting up a custom tournament.</p>
<h2>How to Make Predictions</h2>
<p>The list of matches for a specific date becomes available <strong>3 calendar days</strong> in advance.
At midnight on the match day the prediction window closes — it is no longer possible to add
or change a prediction for that day.</p>
<div class="note">Example: for matches on March 10th, predictions can be made from March 7th until 00:00 on March 10th.</div>
<p>Results are checked and points are awarded <strong>automatically once per day</strong> after
the relevant matches have finished.</p>
<h2>Individual Play</h2>
<p>After registration every player gets a personal account. In the <strong>&laquo;My Competitions&raquo;</strong>
section you can select the leagues and tournaments whose matches you want to predict.
Once selected, the <strong>&laquo;Matches&raquo;</strong> tab shows the upcoming fixtures with score input fields.</p>
<div class="note">Changes to your competition selection (adding or removing leagues) take effect the <strong>following day</strong>, after the nightly system update.</div>
<p>Your personal statistics include:</p>
<ul>
<li>Total number of predictions made</li>
<li>Total number of correctly guessed matches (all time)</li>
<li>Prediction accuracy percentage</li>
<li>Position in the global player ranking</li>
</ul>
<p>Statistics accumulate continuously from the moment of registration — there are no resets.</p>
<h2>Player Ranking</h2>
<p>The global ranking of all players is updated every day after results are processed.
A player's position is determined by the following sequence of criteria:</p>
<ol>
<li>Highest number of correctly guessed matches <strong>of all time</strong></li>
<li>In case of a tie — higher <strong>prediction accuracy</strong> percentage</li>
<li>In case of a tie — greater <strong>total number of predictions made</strong></li>
<li>If all criteria are equal — players share the same position</li>
</ol>
<h2>Group Play</h2>
<p>In addition to the individual mode, you can create a group and compete with friends.
The group leader sets up a <strong>tournament</strong>: selects the leagues and competitions
to be counted, and specifies the start and end dates. During the tournament a separate
<strong>group ranking</strong> is maintained — only matches from the leader's chosen leagues,
played within the specified period, are counted. At the end of the tournament the group
winner is determined.</p>
<div class="note">When a group leader creates a new tournament, the new matches will appear in group members' pages starting from the <strong>following day</strong>.</div>
<p>Limitations:</p>
<ul>
<li>A player can be the leader of at most <strong>3 groups</strong></li>
<li>Each group can have at most <strong>3 active or upcoming tournaments</strong> at the same time</li>
</ul>
<h2>Joining a Group</h2>
<p>There is no public list of groups. To join a group you need to know its name —
you can get it from the group leader or its members.</p>
<p>In your personal account, open the <strong>&laquo;My Groups&raquo;</strong> section — there you will find
a search field. Type the exact group name and press <strong>&laquo;Search&raquo;</strong> or <strong>Enter</strong>.
If the group exists it will appear in the results, and you can send a join request.
The group leader will then <strong>accept or decline</strong> your request.</p>
<div class="note">If you are already a member of the group, or have a pending request that has not yet been reviewed,
a new request will not be accepted.</div>
<h2>Tournament Management (for group leaders)</h2>
<p>The group leader can edit tournament dates within certain restrictions:</p>
<ul>
<li><strong>Start date</strong> — can only be changed before the tournament has begun</li>
<li><strong>End date</strong> — can be changed as long as the final scoring night has not yet passed.
This allows extending a tournament if the original end date was set incorrectly</li>
</ul>
<p>The leader can also <strong>delete a tournament</strong> or the entire group if needed.</p>
<h2>Telegram Notifications</h2>
<p>In your personal account there is a <strong>&laquo;Link Telegram&raquo;</strong> button. Clicking it generates a one-time link — open it in Telegram and send the displayed command to the bot. Once connected, the bot will send you a message every day after the nightly update, confirming that yesterday's results have been processed and new predictions are ready to submit.</p>
<p>To disconnect the bot, click the button again (it will switch to <strong>&laquo;Disconnect Telegram&raquo;</strong>) or send <strong>/stop</strong> to the bot directly in Telegram.</p>
<h2>Bug Reports</h2>
<p>If you notice a bug or incorrect behaviour, you can report it directly from your personal account using the <strong>&laquo;Report a bug&raquo;</strong> button. Your message will be delivered instantly to the administrator via Telegram. The feature is available to all registered users.</p>`,

  uk: `
<h1>\u041f\u0440\u0430\u0432\u0438\u043b\u0430 \u0433\u0440\u0438</h1>
<h2>\u041f\u0440\u043e \u0433\u0440\u0443</h2>
<p>Sport Predictions \u2014 \u0446\u0435 \u0433\u0440\u0430, \u0434\u0435 \u0432\u0438 \u043f\u0440\u043e\u0433\u043d\u043e\u0437\u0443\u0454\u0442\u0435 \u0442\u043e\u0447\u043d\u0438\u0439 \u0440\u0430\u0445\u0443\u043d\u043e\u043a \u0444\u0443\u0442\u0431\u043e\u043b\u044c\u043d\u0438\u0445 \u043c\u0430\u0442\u0447\u0456\u0432, \u0437\u0456\u0433\u0440\u0430\u043d\u0438\u0445 \u043f\u0440\u043e\u0442\u044f\u0433\u043e\u043c \u043e\u0441\u043d\u043e\u0432\u043d\u043e\u0433\u043e \u0447\u0430\u0441\u0443 (90 \u0445\u0432\u0438\u043b\u0438\u043d). \u0417\u0430 \u043a\u043e\u0436\u043d\u0438\u0439 \u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u043e \u0432\u0433\u0430\u0434\u0430\u043d\u0438\u0439 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u0432\u0438 \u043e\u0442\u0440\u0438\u043c\u0443\u0454\u0442\u0435 <strong>1 \u0431\u0430\u043b</strong>. \u0413\u0440\u0430\u0432\u0446\u0456 \u043c\u043e\u0436\u0443\u0442\u044c \u0437\u043c\u0430\u0433\u0430\u0442\u0438\u0441\u044c \u0456\u043d\u0434\u0438\u0432\u0456\u0434\u0443\u0430\u043b\u044c\u043d\u043e \u2014 \u043e\u0431\u0438\u0440\u0430\u044e\u0447\u0438 \u0443\u043b\u044e\u0431\u043b\u0435\u043d\u0456 \u043b\u0456\u0433\u0438 \u0432 \u043e\u0441\u043e\u0431\u0438\u0441\u0442\u043e\u043c\u0443 \u043a\u0430\u0431\u0456\u043d\u0435\u0442\u0456 \u2014 \u0430\u0431\u043e \u0432 \u0433\u0440\u0443\u043f\u0430\u0445 \u0437 \u0434\u0440\u0443\u0437\u044f\u043c\u0438, \u043d\u0430\u043b\u0430\u0448\u0442\u0443\u0432\u0430\u0432\u0448\u0438 \u0432\u043b\u0430\u0441\u043d\u0438\u0439 \u0442\u0443\u0440\u043d\u0456\u0440.</p>
<h2>\u042f\u043a \u0440\u043e\u0431\u0438\u0442\u0438 \u043f\u0440\u043e\u0433\u043d\u043e\u0437\u0438</h2>
<p>\u0421\u043f\u0438\u0441\u043e\u043a \u043c\u0430\u0442\u0447\u0456\u0432 \u043d\u0430 \u043f\u0435\u0432\u043d\u0443 \u0434\u0430\u0442\u0443 \u0441\u0442\u0430\u0454 \u0434\u043e\u0441\u0442\u0443\u043f\u043d\u0438\u043c <strong>\u0437\u0430 3 \u043a\u0430\u043b\u0435\u043d\u0434\u0430\u0440\u043d\u0456 \u0434\u043d\u0456</strong> \u043d\u0430\u043f\u0435\u0440\u0435\u0434. \u041e\u043f\u0456\u0432\u043d\u043e\u0447\u0456 \u0432 \u0434\u0435\u043d\u044c \u043c\u0430\u0442\u0447\u0443 \u0432\u0456\u043a\u043d\u043e \u043f\u0440\u043e\u0433\u043d\u043e\u0437\u0443\u0432\u0430\u043d\u043d\u044f \u0437\u0430\u043a\u0440\u0438\u0432\u0430\u0454\u0442\u044c\u0441\u044f \u2014 \u0434\u043e\u0434\u0430\u0442\u0438 \u0430\u0431\u043e \u0437\u043c\u0456\u043d\u0438\u0442\u0438 \u043f\u0440\u043e\u0433\u043d\u043e\u0437 \u043d\u0430 \u0446\u0435\u0439 \u0434\u0435\u043d\u044c \u0432\u0436\u0435 \u043d\u0435\u043c\u043e\u0436\u043b\u0438\u0432\u043e.</p>
<div class="note">\u041f\u0440\u0438\u043a\u043b\u0430\u0434: \u0434\u043b\u044f \u043c\u0430\u0442\u0447\u0456\u0432 10 \u0431\u0435\u0440\u0435\u0437\u043d\u044f \u043f\u0440\u043e\u0433\u043d\u043e\u0437\u0438 \u043c\u043e\u0436\u043d\u0430 \u0440\u043e\u0431\u0438\u0442\u0438 \u0437 7 \u0431\u0435\u0440\u0435\u0437\u043d\u044f \u0434\u043e 00:00 10 \u0431\u0435\u0440\u0435\u0437\u043d\u044f.</div>
<p>\u0420\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u0438 \u043f\u0435\u0440\u0435\u0432\u0456\u0440\u044f\u044e\u0442\u044c\u0441\u044f \u0456 \u0431\u0430\u043b\u0438 \u043d\u0430\u0440\u0430\u0445\u043e\u0432\u0443\u044e\u0442\u044c\u0441\u044f <strong>\u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u043d\u043e \u0440\u0430\u0437 \u043d\u0430 \u0434\u0435\u043d\u044c</strong> \u043f\u0456\u0441\u043b\u044f \u0437\u0430\u0432\u0435\u0440\u0448\u0435\u043d\u043d\u044f \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u043d\u0438\u0445 \u043c\u0430\u0442\u0447\u0456\u0432.</p>
<h2>\u0406\u043d\u0434\u0438\u0432\u0456\u0434\u0443\u0430\u043b\u044c\u043d\u0430 \u0433\u0440\u0430</h2>
<p>\u041f\u0456\u0441\u043b\u044f \u0440\u0435\u0454\u0441\u0442\u0440\u0430\u0446\u0456\u0457 \u043a\u043e\u0436\u0435\u043d \u0433\u0440\u0430\u0432\u0435\u0446\u044c \u043e\u0442\u0440\u0438\u043c\u0443\u0454 \u043e\u0441\u043e\u0431\u0438\u0441\u0442\u0438\u0439 \u043a\u0430\u0431\u0456\u043d\u0435\u0442. \u0423 \u0440\u043e\u0437\u0434\u0456\u043b\u0456 <strong>&laquo;\u041c\u043e\u0457 \u0437\u043c\u0430\u0433\u0430\u043d\u043d\u044f&raquo;</strong> \u043c\u043e\u0436\u043d\u0430 \u043e\u0431\u0440\u0430\u0442\u0438 \u043b\u0456\u0433\u0438 \u0442\u0430 \u0442\u0443\u0440\u043d\u0456\u0440\u0438, \u043c\u0430\u0442\u0447\u0456 \u044f\u043a\u0438\u0445 \u0432\u0438 \u0445\u043e\u0447\u0435\u0442\u0435 \u043f\u0440\u043e\u0433\u043d\u043e\u0437\u0443\u0432\u0430\u0442\u0438. \u041f\u0456\u0441\u043b\u044f \u0432\u0438\u0431\u043e\u0440\u0443 \u0443 \u0432\u043a\u043b\u0430\u0434\u0446\u0456 <strong>&laquo;\u041c\u0430\u0442\u0447\u0456&raquo;</strong> \u0432\u0456\u0434\u043e\u0431\u0440\u0430\u0436\u0430\u044e\u0442\u044c\u0441\u044f \u043c\u0430\u0439\u0431\u0443\u0442\u043d\u0456 \u0437\u0443\u0441\u0442\u0440\u0456\u0447\u0456 \u0437 \u043f\u043e\u043b\u044f\u043c\u0438 \u0434\u043b\u044f \u0432\u0432\u0435\u0434\u0435\u043d\u043d\u044f \u0440\u0430\u0445\u0443\u043d\u043a\u0443.</p>
<div class="note">\u0417\u043c\u0456\u043d\u0438 \u0443 \u0432\u0438\u0431\u043e\u0440\u0456 \u0437\u043c\u0430\u0433\u0430\u043d\u044c (\u0434\u043e\u0434\u0430\u0432\u0430\u043d\u043d\u044f \u0430\u0431\u043e \u0432\u0438\u0434\u0430\u043b\u0435\u043d\u043d\u044f \u043b\u0456\u0433) \u043d\u0430\u0431\u0443\u0432\u0430\u044e\u0442\u044c \u0447\u0438\u043d\u043d\u043e\u0441\u0442\u0456 <strong>\u043d\u0430\u0441\u0442\u0443\u043f\u043d\u043e\u0433\u043e \u0434\u043d\u044f</strong> \u043f\u0456\u0441\u043b\u044f \u043d\u0456\u0447\u043d\u043e\u0433\u043e \u043e\u043d\u043e\u0432\u043b\u0435\u043d\u043d\u044f \u0441\u0438\u0441\u0442\u0435\u043c\u0438.</div>
<p>\u0412\u0430\u0448\u0430 \u043e\u0441\u043e\u0431\u0438\u0441\u0442\u0430 \u0441\u0442\u0430\u0442\u0438\u0441\u0442\u0438\u043a\u0430 \u0432\u043a\u043b\u044e\u0447\u0430\u0454:</p>
<ul>
<li>\u0417\u0430\u0433\u0430\u043b\u044c\u043d\u0430 \u043a\u0456\u043b\u044c\u043a\u0456\u0441\u0442\u044c \u0437\u0440\u043e\u0431\u043b\u0435\u043d\u0438\u0445 \u043f\u0440\u043e\u0433\u043d\u043e\u0437\u0456\u0432</li>
<li>\u0417\u0430\u0433\u0430\u043b\u044c\u043d\u0430 \u043a\u0456\u043b\u044c\u043a\u0456\u0441\u0442\u044c \u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u043e \u0432\u0433\u0430\u0434\u0430\u043d\u0438\u0445 \u043c\u0430\u0442\u0447\u0456\u0432 (\u0437\u0430 \u0432\u0435\u0441\u044c \u0447\u0430\u0441)</li>
<li>\u0412\u0456\u0434\u0441\u043e\u0442\u043e\u043a \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u0456 \u043f\u0440\u043e\u0433\u043d\u043e\u0437\u0456\u0432</li>
<li>\u041f\u043e\u0437\u0438\u0446\u0456\u044f \u0432 \u0433\u043b\u043e\u0431\u0430\u043b\u044c\u043d\u043e\u043c\u0443 \u0440\u0435\u0439\u0442\u0438\u043d\u0433\u0443 \u0433\u0440\u0430\u0432\u0446\u0456\u0432</li>
</ul>
<p>\u0421\u0442\u0430\u0442\u0438\u0441\u0442\u0438\u043a\u0430 \u043d\u0430\u043a\u043e\u043f\u0438\u0447\u0443\u0454\u0442\u044c\u0441\u044f \u0431\u0435\u0437\u043f\u0435\u0440\u0435\u0440\u0432\u043d\u043e \u0437 \u043c\u043e\u043c\u0435\u043d\u0442\u0443 \u0440\u0435\u0454\u0441\u0442\u0440\u0430\u0446\u0456\u0457 \u2014 \u0441\u043a\u0438\u0434\u0430\u043d\u044c \u043d\u0435\u043c\u0430\u0454.</p>
<h2>\u0420\u0435\u0439\u0442\u0438\u043d\u0433 \u0433\u0440\u0430\u0432\u0446\u0456\u0432</h2>
<p>\u0413\u043b\u043e\u0431\u0430\u043b\u044c\u043d\u0438\u0439 \u0440\u0435\u0439\u0442\u0438\u043d\u0433 \u0432\u0441\u0456\u0445 \u0433\u0440\u0430\u0432\u0446\u0456\u0432 \u043e\u043d\u043e\u0432\u043b\u044e\u0454\u0442\u044c\u0441\u044f \u0449\u043e\u0434\u043d\u044f \u043f\u0456\u0441\u043b\u044f \u043e\u0431\u0440\u043e\u0431\u043a\u0438 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u0456\u0432. \u041f\u043e\u0437\u0438\u0446\u0456\u044f \u0433\u0440\u0430\u0432\u0446\u044f \u0432\u0438\u0437\u043d\u0430\u0447\u0430\u0454\u0442\u044c\u0441\u044f \u043d\u0430\u0441\u0442\u0443\u043f\u043d\u043e\u044e \u043f\u043e\u0441\u043b\u0456\u0434\u043e\u0432\u043d\u0456\u0441\u0442\u044e \u043a\u0440\u0438\u0442\u0435\u0440\u0456\u0457\u0432:</p>
<ol>
<li>\u041d\u0430\u0439\u0431\u0456\u043b\u044c\u0448\u0430 \u043a\u0456\u043b\u044c\u043a\u0456\u0441\u0442\u044c \u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u043e \u0432\u0433\u0430\u0434\u0430\u043d\u0438\u0445 \u043c\u0430\u0442\u0447\u0456\u0432 <strong>\u0437\u0430 \u0432\u0435\u0441\u044c \u0447\u0430\u0441</strong></li>
<li>\u0423 \u0440\u0430\u0437\u0456 \u0440\u0456\u0432\u043d\u043e\u0441\u0442\u0456 \u2014 \u0432\u0438\u0449\u0438\u0439 <strong>\u0432\u0456\u0434\u0441\u043e\u0442\u043e\u043a \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u0456</strong> \u043f\u0440\u043e\u0433\u043d\u043e\u0437\u0456\u0432</li>
<li>\u0423 \u0440\u0430\u0437\u0456 \u0440\u0456\u0432\u043d\u043e\u0441\u0442\u0456 \u2014 \u0431\u0456\u043b\u044c\u0448\u0430 <strong>\u0437\u0430\u0433\u0430\u043b\u044c\u043d\u0430 \u043a\u0456\u043b\u044c\u043a\u0456\u0441\u0442\u044c \u0437\u0440\u043e\u0431\u043b\u0435\u043d\u0438\u0445 \u043f\u0440\u043e\u0433\u043d\u043e\u0437\u0456\u0432</strong></li>
<li>\u042f\u043a\u0449\u043e \u0432\u0441\u0456 \u043a\u0440\u0438\u0442\u0435\u0440\u0456\u0457 \u0440\u0456\u0432\u043d\u0456 \u2014 \u0433\u0440\u0430\u0432\u0446\u0456 \u0434\u0456\u043b\u044f\u0442\u044c \u043e\u0434\u043d\u0430\u043a\u043e\u0432\u0443 \u043f\u043e\u0437\u0438\u0446\u0456\u044e</li>
</ol>
<h2>\u0413\u0440\u0443\u043f\u043e\u0432\u0430 \u0433\u0440\u0430</h2>
<p>\u041e\u043a\u0440\u0456\u043c \u0456\u043d\u0434\u0438\u0432\u0456\u0434\u0443\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u0440\u0435\u0436\u0438\u043c\u0443, \u0432\u0438 \u043c\u043e\u0436\u0435\u0442\u0435 \u0441\u0442\u0432\u043e\u0440\u0438\u0442\u0438 \u0433\u0440\u0443\u043f\u0443 \u0442\u0430 \u0437\u043c\u0430\u0433\u0430\u0442\u0438\u0441\u044c \u0437 \u0434\u0440\u0443\u0437\u044f\u043c\u0438. \u041b\u0456\u0434\u0435\u0440 \u0433\u0440\u0443\u043f\u0438 \u043d\u0430\u043b\u0430\u0448\u0442\u043e\u0432\u0443\u0454 <strong>\u0442\u0443\u0440\u043d\u0456\u0440</strong>: \u043e\u0431\u0438\u0440\u0430\u0454 \u043b\u0456\u0433\u0438 \u0442\u0430 \u0437\u043c\u0430\u0433\u0430\u043d\u043d\u044f, \u044f\u043a\u0456 \u0431\u0443\u0434\u0443\u0442\u044c \u0432\u0440\u0430\u0445\u043e\u0432\u0443\u0432\u0430\u0442\u0438\u0441\u044f, \u0442\u0430 \u0432\u043a\u0430\u0437\u0443\u0454 \u0434\u0430\u0442\u0438 \u043f\u043e\u0447\u0430\u0442\u043a\u0443 \u0456 \u0437\u0430\u043a\u0456\u043d\u0447\u0435\u043d\u043d\u044f. \u041f\u0440\u043e\u0442\u044f\u0433\u043e\u043c \u0442\u0443\u0440\u043d\u0456\u0440\u0443 \u0432\u0435\u0434\u0435\u0442\u044c\u0441\u044f \u043e\u043a\u0440\u0435\u043c\u0438\u0439 <strong>\u0433\u0440\u0443\u043f\u043e\u0432\u0438\u0439 \u0440\u0435\u0439\u0442\u0438\u043d\u0433</strong> \u2014 \u0432\u0440\u0430\u0445\u043e\u0432\u0443\u044e\u0442\u044c\u0441\u044f \u043b\u0438\u0448\u0435 \u043c\u0430\u0442\u0447\u0456 \u0437 \u043e\u0431\u0440\u0430\u043d\u0438\u0445 \u043b\u0456\u0434\u0435\u0440\u043e\u043c \u043b\u0456\u0433, \u0437\u0456\u0433\u0440\u0430\u043d\u0456 \u0432 \u043c\u0435\u0436\u0430\u0445 \u0437\u0430\u0437\u043d\u0430\u0447\u0435\u043d\u043e\u0433\u043e \u043f\u0435\u0440\u0456\u043e\u0434\u0443. \u041f\u0456\u0441\u043b\u044f \u0437\u0430\u0432\u0435\u0440\u0448\u0435\u043d\u043d\u044f \u0442\u0443\u0440\u043d\u0456\u0440\u0443 \u0432\u0438\u0437\u043d\u0430\u0447\u0430\u0454\u0442\u044c\u0441\u044f \u043f\u0435\u0440\u0435\u043c\u043e\u0436\u0435\u0446\u044c \u0433\u0440\u0443\u043f\u0438.</p>
<div class="note">\u041a\u043e\u043b\u0438 \u043b\u0456\u0434\u0435\u0440 \u0433\u0440\u0443\u043f\u0438 \u0441\u0442\u0432\u043e\u0440\u044e\u0454 \u043d\u043e\u0432\u0438\u0439 \u0442\u0443\u0440\u043d\u0456\u0440, \u043c\u0430\u0442\u0447\u0456 \u0437'\u044f\u0432\u043b\u044f\u0442\u044c\u0441\u044f \u043d\u0430 \u0441\u0442\u043e\u0440\u0456\u043d\u043a\u0430\u0445 \u0443\u0447\u0430\u0441\u043d\u0438\u043a\u0456\u0432 \u0433\u0440\u0443\u043f\u0438 \u043f\u043e\u0447\u0438\u043d\u0430\u044e\u0447\u0438 \u0437 <strong>\u043d\u0430\u0441\u0442\u0443\u043f\u043d\u043e\u0433\u043e \u0434\u043d\u044f</strong>.</div>
<p>\u041e\u0431\u043c\u0435\u0436\u0435\u043d\u043d\u044f:</p>
<ul>
<li>\u0413\u0440\u0430\u0432\u0435\u0446\u044c \u043c\u043e\u0436\u0435 \u0431\u0443\u0442\u0438 \u043b\u0456\u0434\u0435\u0440\u043e\u043c \u043d\u0430\u0439\u0431\u0456\u043b\u044c\u0448\u0435 <strong>3 \u0433\u0440\u0443\u043f</strong></li>
<li>\u041a\u043e\u0436\u043d\u0430 \u0433\u0440\u0443\u043f\u0430 \u043c\u043e\u0436\u0435 \u043c\u0430\u0442\u0438 \u043d\u0430\u0439\u0431\u0456\u043b\u044c\u0448\u0435 <strong>3 \u0430\u043a\u0442\u0438\u0432\u043d\u0438\u0445 \u0430\u0431\u043e \u043c\u0430\u0439\u0431\u0443\u0442\u043d\u0456\u0445 \u0442\u0443\u0440\u043d\u0456\u0440\u0456\u0432</strong> \u043e\u0434\u043d\u043e\u0447\u0430\u0441\u043d\u043e</li>
</ul>
<h2>\u0412\u0441\u0442\u0443\u043f \u0434\u043e \u0433\u0440\u0443\u043f\u0438</h2>
<p>\u041f\u0443\u0431\u043b\u0456\u0447\u043d\u043e\u0433\u043e \u0441\u043f\u0438\u0441\u043a\u0443 \u0433\u0440\u0443\u043f \u043d\u0435\u043c\u0430\u0454. \u0429\u043e\u0431 \u043f\u0440\u0438\u0454\u0434\u043d\u0430\u0442\u0438\u0441\u044f \u0434\u043e \u0433\u0440\u0443\u043f\u0438, \u0432\u0430\u043c \u043f\u043e\u0442\u0440\u0456\u0431\u043d\u043e \u0437\u043d\u0430\u0442\u0438 \u0457\u0457 \u043d\u0430\u0437\u0432\u0443 \u2014 \u043e\u0442\u0440\u0438\u043c\u0430\u0442\u0438 \u0457\u0457 \u043c\u043e\u0436\u043d\u0430 \u0432\u0456\u0434 \u043b\u0456\u0434\u0435\u0440\u0430 \u0433\u0440\u0443\u043f\u0438 \u0430\u0431\u043e \u0457\u0457 \u0443\u0447\u0430\u0441\u043d\u0438\u043a\u0456\u0432.</p>
<p>\u0412 \u043e\u0441\u043e\u0431\u0438\u0441\u0442\u043e\u043c\u0443 \u043a\u0430\u0431\u0456\u043d\u0435\u0442\u0456 \u0432\u0456\u0434\u043a\u0440\u0438\u0439\u0442\u0435 \u0440\u043e\u0437\u0434\u0456\u043b <strong>&laquo;\u041c\u043e\u0457 \u0433\u0440\u0443\u043f\u0438&raquo;</strong> \u2014 \u0442\u0430\u043c \u0454 \u043f\u043e\u043b\u0435 \u043f\u043e\u0448\u0443\u043a\u0443. \u0412\u0432\u0435\u0434\u0456\u0442\u044c \u0442\u043e\u0447\u043d\u0443 \u043d\u0430\u0437\u0432\u0443 \u0433\u0440\u0443\u043f\u0438 \u0442\u0430 \u043d\u0430\u0442\u0438\u0441\u043d\u0456\u0442\u044c <strong>&laquo;\u041f\u043e\u0448\u0443\u043a&raquo;</strong> \u0430\u0431\u043e <strong>Enter</strong>. \u042f\u043a\u0449\u043e \u0433\u0440\u0443\u043f\u0430 \u0456\u0441\u043d\u0443\u0454, \u0432\u043e\u043d\u0430 \u0437'\u044f\u0432\u0438\u0442\u044c\u0441\u044f \u0432 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u0430\u0445, \u0456 \u0432\u0438 \u043c\u043e\u0436\u0435\u0442\u0435 \u043d\u0430\u0434\u0456\u0441\u043b\u0430\u0442\u0438 \u0437\u0430\u043f\u0438\u0442 \u043d\u0430 \u0432\u0441\u0442\u0443\u043f. \u041b\u0456\u0434\u0435\u0440 \u0433\u0440\u0443\u043f\u0438 \u043f\u043e\u0442\u0456\u043c <strong>\u043f\u0440\u0438\u0439\u043c\u0435 \u0430\u0431\u043e \u0432\u0456\u0434\u0445\u0438\u043b\u0438\u0442\u044c</strong> \u0432\u0430\u0448 \u0437\u0430\u043f\u0438\u0442.</p>
<div class="note">\u042f\u043a\u0449\u043e \u0432\u0438 \u0432\u0436\u0435 \u0454 \u0443\u0447\u0430\u0441\u043d\u0438\u043a\u043e\u043c \u0433\u0440\u0443\u043f\u0438 \u0430\u0431\u043e \u043c\u0430\u0454\u0442\u0435 \u043e\u0447\u0456\u043a\u0443\u0432\u0430\u043d\u0438\u0439 \u0437\u0430\u043f\u0438\u0442, \u044f\u043a\u0438\u0439 \u0449\u0435 \u043d\u0435 \u0440\u043e\u0437\u0433\u043b\u044f\u043d\u0443\u0442\u043e, \u043d\u043e\u0432\u0438\u0439 \u0437\u0430\u043f\u0438\u0442 \u043f\u0440\u0438\u0439\u043d\u044f\u0442\u0438\u0439 \u043d\u0435 \u0431\u0443\u0434\u0435.</div>
<h2>\u0423\u043f\u0440\u0430\u0432\u043b\u0456\u043d\u043d\u044f \u0442\u0443\u0440\u043d\u0456\u0440\u043e\u043c (\u0434\u043b\u044f \u043b\u0456\u0434\u0435\u0440\u0456\u0432 \u0433\u0440\u0443\u043f\u0438)</h2>
<p>\u041b\u0456\u0434\u0435\u0440 \u0433\u0440\u0443\u043f\u0438 \u043c\u043e\u0436\u0435 \u0440\u0435\u0434\u0430\u0433\u0443\u0432\u0430\u0442\u0438 \u0434\u0430\u0442\u0438 \u0442\u0443\u0440\u043d\u0456\u0440\u0443 \u0432 \u043c\u0435\u0436\u0430\u0445 \u043f\u0435\u0432\u043d\u0438\u0445 \u043e\u0431\u043c\u0435\u0436\u0435\u043d\u044c:</p>
<ul>
<li><strong>\u0414\u0430\u0442\u0430 \u043f\u043e\u0447\u0430\u0442\u043a\u0443</strong> \u2014 \u043c\u043e\u0436\u043d\u0430 \u0437\u043c\u0456\u043d\u0438\u0442\u0438 \u043b\u0438\u0448\u0435 \u0434\u043e \u043f\u043e\u0447\u0430\u0442\u043a\u0443 \u0442\u0443\u0440\u043d\u0456\u0440\u0443</li>
<li><strong>\u0414\u0430\u0442\u0430 \u0437\u0430\u043a\u0456\u043d\u0447\u0435\u043d\u043d\u044f</strong> \u2014 \u043c\u043e\u0436\u043d\u0430 \u0437\u043c\u0456\u043d\u0438\u0442\u0438, \u043f\u043e\u043a\u0438 \u043e\u0441\u0442\u0430\u043d\u043d\u044f \u043d\u0456\u0447 \u043f\u0456\u0434\u0440\u0430\u0445\u0443\u043d\u043a\u0443 \u0449\u0435 \u043d\u0435 \u043c\u0438\u043d\u0443\u043b\u0430. \u0426\u0435 \u0434\u043e\u0437\u0432\u043e\u043b\u044f\u0454 \u043f\u0440\u043e\u0434\u043e\u0432\u0436\u0438\u0442\u0438 \u0442\u0443\u0440\u043d\u0456\u0440, \u044f\u043a\u0449\u043e \u043f\u043e\u0447\u0430\u0442\u043a\u043e\u0432\u0430 \u0434\u0430\u0442\u0430 \u0437\u0430\u043a\u0456\u043d\u0447\u0435\u043d\u043d\u044f \u0431\u0443\u043b\u0430 \u0432\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d\u0430 \u043d\u0435\u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u043e</li>
</ul>
<p>\u041b\u0456\u0434\u0435\u0440 \u0442\u0430\u043a\u043e\u0436 \u043c\u043e\u0436\u0435 <strong>\u0432\u0438\u0434\u0430\u043b\u0438\u0442\u0438 \u0442\u0443\u0440\u043d\u0456\u0440</strong> \u0430\u0431\u043e \u0432\u0441\u044e \u0433\u0440\u0443\u043f\u0443, \u044f\u043a\u0449\u043e \u0446\u0435 \u043d\u0435\u043e\u0431\u0445\u0456\u0434\u043d\u043e.</p>
<h2>Telegram-\u0441\u043f\u043e\u0432\u0456\u0449\u0435\u043d\u043d\u044f</h2>
<p>\u0412 \u043e\u0441\u043e\u0431\u0438\u0441\u0442\u043e\u043c\u0443 \u043a\u0430\u0431\u0456\u043d\u0435\u0442\u0456 \u0454 \u043a\u043d\u043e\u043f\u043a\u0430 <strong>&laquo;\u041f\u0456\u0434\u043a\u043b\u044e\u0447\u0438\u0442\u0438 Telegram&raquo;</strong>. \u041d\u0430\u0442\u0438\u0441\u043d\u0443\u0432\u0448\u0438 \u0457\u0457, \u0432\u0438 \u043e\u0442\u0440\u0438\u043c\u0430\u0454\u0442\u0435 \u043e\u0434\u043d\u043e\u0440\u0430\u0437\u043e\u0432\u0435 \u043f\u043e\u0441\u0438\u043b\u0430\u043d\u043d\u044f \u2014 \u0432\u0456\u0434\u043a\u0440\u0438\u0439\u0442\u0435 \u0439\u043e\u0433\u043e \u0432 Telegram \u0456 \u043d\u0430\u0434\u0456\u0448\u043b\u0456\u0442\u044c \u0431\u043e\u0442\u0443 \u0432\u0456\u0434\u043e\u0431\u0440\u0430\u0436\u0435\u043d\u0443 \u043a\u043e\u043c\u0430\u043d\u0434\u0443. \u041f\u0456\u0441\u043b\u044f \u043f\u0456\u0434\u043a\u043b\u044e\u0447\u0435\u043d\u043d\u044f \u0431\u043e\u0442 \u0449\u043e\u0434\u043d\u044f, \u043f\u0456\u0441\u043b\u044f \u043d\u0456\u0447\u043d\u043e\u0433\u043e \u043e\u043d\u043e\u0432\u043b\u0435\u043d\u043d\u044f, \u043d\u0430\u0434\u0441\u0438\u043b\u0430\u0442\u0438\u043c\u0435 \u0432\u0430\u043c \u043f\u043e\u0432\u0456\u0434\u043e\u043c\u043b\u0435\u043d\u043d\u044f \u043f\u0440\u043e \u0442\u0435, \u0449\u043e \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u0438 \u0432\u0447\u043e\u0440\u0430\u0448\u043d\u044c\u043e\u0433\u043e \u0434\u043d\u044f \u043e\u0431\u0440\u043e\u0431\u043b\u0435\u043d\u043e \u0456 \u043d\u043e\u0432\u0456 \u043f\u0440\u043e\u0433\u043d\u043e\u0437\u0438 \u0434\u043e\u0441\u0442\u0443\u043f\u043d\u0456 \u0434\u043b\u044f \u0437\u0430\u043f\u043e\u0432\u043d\u0435\u043d\u043d\u044f.</p>
<p>\u0429\u043e\u0431 \u0432\u0456\u0434\u043a\u043b\u044e\u0447\u0438\u0442\u0438 \u0431\u043e\u0442\u0430, \u043d\u0430\u0442\u0438\u0441\u043d\u0456\u0442\u044c \u043a\u043d\u043e\u043f\u043a\u0443 \u0449\u0435 \u0440\u0430\u0437 (\u0432\u043e\u043d\u0430 \u0437\u043c\u0456\u043d\u0438\u0442\u044c\u0441\u044f \u043d\u0430 <strong>&laquo;\u0412\u0456\u0434\u043a\u043b\u044e\u0447\u0438\u0442\u0438 Telegram&raquo;</strong>) \u0430\u0431\u043e \u043d\u0430\u0434\u0456\u0448\u043b\u0456\u0442\u044c <strong>/stop</strong> \u0431\u043e\u0442\u0443 \u0431\u0435\u0437\u043f\u043e\u0441\u0435\u0440\u0435\u0434\u043d\u044c\u043e \u0432 Telegram.</p>
<h2>\u041f\u043e\u0432\u0456\u0434\u043e\u043c\u043b\u0435\u043d\u043d\u044f \u043f\u0440\u043e \u043f\u043e\u043c\u0438\u043b\u043a\u0438</h2>
<p>\u042f\u043a\u0449\u043e \u0432\u0438 \u043f\u043e\u043c\u0456\u0442\u0438\u043b\u0438 \u043f\u043e\u043c\u0438\u043b\u043a\u0443 \u0430\u0431\u043e \u043d\u0435\u043a\u043e\u0440\u0435\u043a\u0442\u043d\u0443 \u0440\u043e\u0431\u043e\u0442\u0443 \u0441\u0430\u0439\u0442\u0443, \u0432\u0438 \u043c\u043e\u0436\u0435\u0442\u0435 \u043f\u043e\u0432\u0456\u0434\u043e\u043c\u0438\u0442\u0438 \u043f\u0440\u043e \u0446\u0435 \u043f\u0440\u044f\u043c\u043e \u0437 \u043e\u0441\u043e\u0431\u0438\u0441\u0442\u043e\u0433\u043e \u043a\u0430\u0431\u0456\u043d\u0435\u0442\u0443 \u0437\u0430 \u0434\u043e\u043f\u043e\u043c\u043e\u0433\u043e\u044e \u043a\u043d\u043e\u043f\u043a\u0438 <strong>&laquo;\u041f\u043e\u0432\u0456\u0434\u043e\u043c\u0438\u0442\u0438 \u043f\u0440\u043e \u043f\u043e\u043c\u0438\u043b\u043a\u0443&raquo;</strong>. \u0412\u0430\u0448\u0435 \u043f\u043e\u0432\u0456\u0434\u043e\u043c\u043b\u0435\u043d\u043d\u044f \u043c\u0438\u0442\u0442\u0454\u0432\u043e \u043d\u0430\u0434\u0456\u0439\u0434\u0435 \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0442\u043e\u0440\u0443 \u0447\u0435\u0440\u0435\u0437 Telegram. \u0424\u0443\u043d\u043a\u0446\u0456\u044f \u0434\u043e\u0441\u0442\u0443\u043f\u043d\u0430 \u0432\u0441\u0456\u043c \u0437\u0430\u0440\u0435\u0454\u0441\u0442\u0440\u043e\u0432\u0430\u043d\u0438\u043c \u043a\u043e\u0440\u0438\u0441\u0442\u0443\u0432\u0430\u0447\u0430\u043c.</p>`
};

function t(key) {
  const lang = localStorage.getItem('lang') || 'en';
  const dict = translations[lang] || translations['en'];
  return dict[key] !== undefined ? dict[key] : (translations['en'][key] !== undefined ? translations['en'][key] : key);
}

function applyTranslations(lang) {
  const dict = translations[lang] || translations['en'];
  document.querySelectorAll('[data-i18n]').forEach(function(el) {
    const key = el.getAttribute('data-i18n');
    const val = dict[key];
    if (val === undefined) return;
    if (el.tagName === 'INPUT' || el.tagName === 'TEXTAREA') {
      el.placeholder = val;
    } else {
      el.textContent = val;
    }
  });
  const rulesContainer = document.querySelector('.rules-container');
  if (rulesContainer && rulesContent[lang]) {
    rulesContainer.innerHTML = rulesContent[lang];
  }
}

function setLanguage(lang) {
  localStorage.setItem('lang', lang);
  const enBtn = document.getElementById('lang-en');
  const ukBtn = document.getElementById('lang-uk');
  if (enBtn) enBtn.className = 'lang-btn ' + (lang === 'en' ? 'active' : 'inactive');
  if (ukBtn) ukBtn.className = 'lang-btn ' + (lang === 'uk' ? 'active' : 'inactive');
  applyTranslations(lang);
  if (typeof window.onI18nChange === 'function') {
    window.onI18nChange(lang);
  }
  if (localStorage.getItem('userName')) {
    fetch('/api/v0/user/language', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ language: lang })
    }).catch(function(err) { console.warn('Failed to save language preference:', err); });
  }
}

function initLang() {
  const lang = localStorage.getItem('lang') || 'en';
  setLanguage(lang);
}

function openBugReport() {
  const modal = document.getElementById('bug-report-modal');
  const textarea = document.getElementById('bug-report-textarea');
  if (!modal || !textarea) return;
  textarea.value = '';
  textarea.style.height = 'auto';
  document.getElementById('bug-report-status').textContent = '';
  applyTranslations(localStorage.getItem('lang') || 'en');
  modal.style.display = 'flex';
  modal.onclick = function(e) { if (e.target === modal) closeBugReport(); };
}

function closeBugReport() {
  const modal = document.getElementById('bug-report-modal');
  if (modal) modal.style.display = 'none';
}

function sendBugReport() {
  const textarea = document.getElementById('bug-report-textarea');
  const statusEl = document.getElementById('bug-report-status');
  const message = textarea.value.trim();
  if (!message) {
    statusEl.textContent = t('bug.empty');
    statusEl.style.color = '#e74c3c';
    return;
  }
  const sendBtn = document.querySelector('.bug-send-btn');
  sendBtn.disabled = true;
  fetch('/api/v0/bug-report', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ message: message })
  }).then(function(res) {
    if (res.ok) {
      statusEl.textContent = t('bug.success');
      statusEl.style.color = '#27ae60';
      setTimeout(closeBugReport, 2000);
    } else {
      statusEl.textContent = t('bug.error');
      statusEl.style.color = '#e74c3c';
    }
  }).catch(function() {
    statusEl.textContent = t('bug.error');
    statusEl.style.color = '#e74c3c';
  }).finally(function() { sendBtn.disabled = false; });
}

(function() { initLang(); })();
